import{_ as e,o as t,c as l,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"13.6 小结","description":"","frontmatter":{},"headers":[],"relativePath":"13/6.md","filePath":"13/6.md","lastUpdated":null}'),r={name:"13/6.md"};function i(n,a,s,_,d,c){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="_13-6-小结" tabindex="-1">13.6 小结 <a class="header-anchor" href="#_13-6-小结" aria-label="Permalink to &quot;13.6 小结&quot;">​</a></h1><p>这一章我们主要介绍了如何实现一个基础的Go语言框架，框架包含有路由设计，由于Go内置的http包中路由的一些不足点，我们设计了动态路由规则，然后介绍了MVC模式中的Controller设计，controller实现了REST的实现，这个主要思路来源于tornado框架，然后设计实现了模板的layout以及自动化渲染等技术，主要采用了Go内置的模板引擎，最后我们介绍了一些辅助的日志、配置等信息的设计，通过这些设计我们实现了一个基础的框架beego，目前该框架已经开源在GitHub，最后我们通过beego实现了一个博客系统，通过实例代码详细的展现了如何快速的开发一个站点。</p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/13/5.html">实现博客的增删改</a></li><li>下一节: <a href="/14/0.html">扩展Web框架</a></li></ul>',4)])])}const u=e(r,[["render",i]]);export{p as __pageData,u as default};
